SELECT /* base.ec.pd :: PdProdQna :: selectList */ q.* , ste.site_nm AS site_nm , prd.prod_nm AS prod_nm , mem.member_nm AS member_nm , ord.member_nm AS order_nm , usr.user_nm AS answ_user_nm , cd_pqt.code_label AS qna_type_cd_nm FROM pd_prod_qna q LEFT JOIN sy_site ste ON ste.site_id = q.site_id LEFT JOIN pd_prod prd ON prd.prod_id = q.prod_id LEFT JOIN mb_member mem ON mem.member_id = q.member_id LEFT JOIN od_order ord ON ord.order_id = q.order_id LEFT JOIN sy_user usr ON usr.user_id = q.answ_user_id LEFT JOIN sy_code cd_pqt ON cd_pqt.code_grp = 'PROD_QNA_TYPE' AND cd_pqt.code_value = q.qna_type_cd
ORDER BY q.qna_id ASC ORDER BY q.qna_id DESC ORDER BY q.qna_title ASC ORDER BY q.qna_title DESC ORDER BY q.reg_date ASC ORDER BY q.reg_date DESC ORDER BY q.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

