site_id = #{siteId}, prod_id = #{prodId}, sku_id = #{skuId}, member_id = #{memberId}, order_id = #{orderId}, qna_type_cd = #{qnaTypeCd}, qna_title = #{qnaTitle}, qna_content = #{qnaContent}, scrt_yn = #{scrtYn}, answ_yn = #{answYn}, answ_content = #{answContent}, answ_date = #{answDate}, answ_user_id = #{answUserId}, disp_yn = #{dispYn}, use_yn = #{useYn}, upd_by = #{updBy}, upd_date = #{updDate},
